        Some(content) if !content.is_empty() => {
            std::fs::write(&path, content)?;
        },
        _ => {
            // Write an empty file rather than deleting so `load_soul()`
            // distinguishes "user cleared soul" from "file never existed".
            std::fs::write(&path, "")?;
        },
    }
    Ok(path)
}

