use {anyhow::Result, clap::Subcommand, std::time::Duration};

/// `moltis node` subcommands — manage remote nodes.
#[derive(Subcommand)]
pub enum NodeAction {
    /// Generate a device token so a remote machine can connect as a node.
    ///
    /// Prints the token and the `moltis node add` command to run on the
    /// remote machine. This is the CLI equivalent of clicking "Generate Token"
    /// on the web UI Nodes page.
    GenerateToken {
        /// Display name for the new device.
        #[arg(long)]
        name: Option<String>,
        /// Gateway HTTP URL (used to call the RPC).
        #[arg(long, default_value = "http://localhost:9090")]
        host: String,
        /// API key or password for authentication.
        #[arg(long, env = "MOLTIS_API_KEY")]
        api_key: Option<String>,
    },

    /// List all connected nodes.
    List {
        /// Gateway HTTP URL.
        #[arg(long, default_value = "http://localhost:9090")]
        host: String,
        /// API key or password for authentication.
        #[arg(long, env = "MOLTIS_API_KEY")]
        api_key: Option<String>,
    },

    /// Join this machine to a gateway as a node.
    ///
    /// Saves the connection parameters and installs an OS service (launchd on
    /// macOS, systemd on Linux) that starts on boot and reconnects on failure.
    /// Pass --foreground to run in the current terminal instead.
    Add {
        /// Gateway WebSocket URL (e.g. ws://your-server:9090/ws).
        #[arg(long, env = "MOLTIS_GATEWAY_URL")]
        host: String,
        /// Device token from `moltis node generate-token`.
        #[arg(long, env = "MOLTIS_DEVICE_TOKEN")]
        token: String,
        /// Display name for this node.
        #[arg(long)]
        name: Option<String>,
        /// Custom node ID (defaults to a random UUID).
        #[arg(long)]
        node_id: Option<String>,
        /// Working directory for command execution.
        #[arg(long)]
        working_dir: Option<String>,
        /// Maximum command timeout in seconds.
        #[arg(long, default_value = "300")]
        timeout: u64,
        /// Run in the foreground instead of installing as a service.
        #[arg(long)]
        foreground: bool,
    },

    /// Run the node agent using saved config from `node.json`.
    ///
    /// This is the command invoked by the OS service (launchd / systemd).
    /// It reads connection parameters from `~/.moltis/node.json`, which
    /// is written by `moltis node add`.
    Run {
        /// Override the maximum command timeout in seconds.
        #[arg(long)]
        timeout: Option<u64>,
    },

    /// Disconnect this machine and remove the node service.
    Remove,

    /// Show the current node connection info and service status.
    Status,

    /// Print the path to the node log file.
    Logs,
}

pub async fn handle_node(action: NodeAction) -> Result<()> {
    match action {
        NodeAction::GenerateToken {
            name,
            host,
            api_key,
        } => cmd_generate_token(&host, api_key.as_deref(), name.as_deref()).await,

        NodeAction::List { host, api_key } => cmd_list(&host, api_key.as_deref()).await,

        NodeAction::Add {
            host,
            token,
            name,
            node_id,
            working_dir,
            timeout,
            foreground,
        } => {
            let resolved_node_id = node_id.unwrap_or_else(|| uuid::Uuid::new_v4().to_string());

            if foreground {
                let config = moltis_node_host::NodeConfig {
                    gateway_url: host,
                    device_token: token,
                    node_id: resolved_node_id,
                    display_name: name,
                    platform: std::env::consts::OS.into(),
                    caps: vec![
                        "system.run".into(),
                        "system.which".into(),
                        "system.providers".into(),
                    ],
                    commands: vec![
                        "system.run".into(),
                        "system.which".into(),
                        "system.providers".into(),
                    ],
                    exec_timeout: Duration::from_secs(timeout),
                    working_dir,
                };

                let node = moltis_node_host::NodeHost::new(config);
                node.run().await
            } else {
                let data_dir = moltis_config::data_dir();
                let svc_config = moltis_node_host::ServiceConfig {
                    gateway_url: host,
                    device_token: token,
                    node_id: Some(resolved_node_id),
                    display_name: name,
                    working_dir,
                    timeout,
                };

                moltis_node_host::service::install(&data_dir, &svc_config)?;
                println!("Node registered and service started.");
                println!(
                    "Logs: {}",
                    moltis_node_host::service::log_path(&data_dir).display()
                );
                Ok(())
            }
        },

        NodeAction::Run { timeout } => {
            let data_dir = moltis_config::data_dir();
            let config = moltis_node_host::ServiceConfig::load(&data_dir)
                .map_err(|e| anyhow::anyhow!(
                    "cannot load node config: {e}\nRun `moltis node add` first to register this machine."
                ))?;

            let exec_timeout = Duration::from_secs(timeout.unwrap_or(config.timeout));

            let node_config = moltis_node_host::NodeConfig {
                gateway_url: config.gateway_url,
                device_token: config.device_token,
                node_id: config.node_id.unwrap_or_else(|| uuid::Uuid::new_v4().to_string()),
                display_name: config.display_name,
                platform: std::env::consts::OS.into(),
                caps: vec![
                    "system.run".into(),
                    "system.which".into(),
                    "system.providers".into(),
                ],
                commands: vec![
                    "system.run".into(),
                    "system.which".into(),
                    "system.providers".into(),
                ],
                exec_timeout,
                working_dir: config.working_dir,
            };

            let node = moltis_node_host::NodeHost::new(node_config);
            node.run().await
        },

        NodeAction::Remove => {
            let data_dir = moltis_config::data_dir();
            moltis_node_host::service::uninstall(&data_dir)?;
            println!("Node removed.");
            Ok(())
        },

        NodeAction::Status => {
            let data_dir = moltis_config::data_dir();
            let config_path = data_dir.join("node.json");

            if !config_path.exists() {
                println!("Not registered as a node.");
                return Ok(());
            }

            let config = moltis_node_host::ServiceConfig::load(&data_dir)?;
            let status = moltis_node_host::service::status()?;

            println!("Gateway: {}", config.gateway_url);
            if let Some(ref name) = config.display_name {
                println!("Name:    {name}");
            }
            println!("Service: {status}");
            Ok(())
        },

        NodeAction::Logs => {
            let data_dir = moltis_config::data_dir();
            println!(
                "{}",
                moltis_node_host::service::log_path(&data_dir).display()
            );
            Ok(())
        },
    }
}

// ── Gateway RPC helpers ─────────────────────────────────────────────────���──

/// Call `device.token.create` on the gateway and print the token + command.
async fn cmd_generate_token(host: &str, api_key: Option<&str>, name: Option<&str>) -> Result<()> {
    let mut params = serde_json::Map::new();
    if let Some(n) = name {
        params.insert("displayName".into(), serde_json::json!(n));
    }
    params.insert("platform".into(), serde_json::json!("remote"));

    let result = gateway_rpc(host, api_key, "device.token.create", params.into()).await?;

    let token = result
        .get("deviceToken")
        .and_then(|v| v.as_str())
        .ok_or_else(|| anyhow::anyhow!("unexpected response: missing deviceToken"))?;

    let ws_url = http_to_ws(host);

    println!("Device token: {token}");
    println!();
    println!("Run this on the remote machine:");
    println!("  moltis node add --host {ws_url} --token {token}");
    println!();
    println!("The token is shown once and cannot be retrieved later.");

    Ok(())
}

/// Call `node.list` on the gateway and print connected nodes.
async fn cmd_list(host: &str, api_key: Option<&str>) -> Result<()> {
    let result = gateway_rpc(host, api_key, "node.list", serde_json::json!({})).await?;

    let nodes = result
        .get("nodes")
        .and_then(|v| v.as_array())
        .cloned()
        .unwrap_or_default();

    if nodes.is_empty() {
        println!("No nodes connected.");
        return Ok(());
    }

    for node in &nodes {
        let id = node.get("nodeId").and_then(|v| v.as_str()).unwrap_or("?");
        let name = node
            .get("displayName")
            .and_then(|v| v.as_str())
            .unwrap_or("(unnamed)");
        let platform = node.get("platform").and_then(|v| v.as_str()).unwrap_or("?");

        println!("{id}  {name}  ({platform})");
    }

    Ok(())
}

/// Send a single RPC request to the gateway over HTTP (JSON-RPC style).
///
/// The gateway exposes RPC methods over the WebSocket protocol, but for
/// one-shot CLI commands we use the `/api/rpc` endpoint when available,
/// falling back to a transient WebSocket connection.
async fn gateway_rpc(
    host: &str,
    api_key: Option<&str>,
    method: &str,
    params: serde_json::Value,
) -> Result<serde_json::Value> {
    let url = format!("{}/api/rpc", host.trim_end_matches('/'));
    let body = serde_json::json!({
        "method": method,
        "params": params,
    });

    let client = reqwest::Client::new();
    let mut req = client.post(&url).json(&body);
    if let Some(key) = api_key {
        req = req.header("Authorization", format!("Bearer {key}"));
    }

    let resp = req
        .send()
        .await
        .map_err(|e| anyhow::anyhow!("cannot reach gateway at {host}: {e}"))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        anyhow::bail!("gateway returned {status}: {body}");
    }

    let result: serde_json::Value = resp.json().await?;

    if let Some(err) = result.get("error") {
        let msg = err
            .get("message")
            .and_then(|v| v.as_str())
            .unwrap_or("unknown error");
        anyhow::bail!("RPC error: {msg}");
    }

    Ok(result.get("payload").cloned().unwrap_or(result))
}

/// Convert `http://host:port` to `ws://host:port/ws`.
fn http_to_ws(http_url: &str) -> String {
    let ws = http_url
        .replace("https://", "wss://")
        .replace("http://", "ws://");
    let base = ws.trim_end_matches('/');
    format!("{base}/ws")
}

#[cfg(test)]
mod tests {
    #![allow(clippy::unwrap_used)]

    use super::*;

    #[test]
    fn http_to_ws_basic() {
        assert_eq!(
            http_to_ws("http://localhost:9090"),
            "ws://localhost:9090/ws"
        );
    }

    #[test]
    fn http_to_ws_https() {
        assert_eq!(
            http_to_ws("https://my-server.com"),
            "wss://my-server.com/ws"
        );
    }

    #[test]
    fn http_to_ws_trailing_slash() {
        assert_eq!(
            http_to_ws("http://localhost:9090/"),
            "ws://localhost:9090/ws"
        );
    }
}

use std::{net::SocketAddr, sync::Arc};

use axum::{
    extract::{ConnectInfo, FromRef, FromRequestParts},
    http::{HeaderMap, StatusCode, request::Parts},
};

#[cfg(any(feature = "web-ui", feature = "vault"))]
use axum::{
    extract::State,
    middleware::Next,
    response::{IntoResponse, Json, Redirect},
};
#[cfg(feature = "web-ui")]
use tracing::warn;

use crate::{
    auth::{AuthIdentity, AuthMethod, CredentialStore},
    server::is_local_connection,
    state::GatewayState,
};

/// Session cookie name.
pub const SESSION_COOKIE: &str = "moltis_session";
const AUTH_SETUP_REQUIRED: &str = "AUTH_SETUP_REQUIRED";
const AUTH_NOT_AUTHENTICATED: &str = "AUTH_NOT_AUTHENTICATED";

// ── AuthResult — single source of truth for auth decisions ──────────────────

/// Outcome of an auth check against a credential store.
#[derive(Debug, Clone)]
pub enum AuthResult {
    /// Request is authorized.
    Allowed(AuthIdentity),
    /// No credentials configured yet; only local connections may pass.
    SetupRequired,
    /// Credentials exist but request is not authenticated.
    Unauthorized,
}

/// Single source of truth for auth decisions.
///
/// Every code path that needs to decide "is this request authenticated?" must
/// call this function instead of reimplementing the logic. This prevents the
/// split-brain bugs that arise when `is_setup_complete()` and `has_password()`
/// diverge (e.g. passkey-only setups).
pub async fn check_auth(
    store: &CredentialStore,
    headers: &HeaderMap,
    is_local: bool,
) -> AuthResult {
    if store.is_auth_disabled() {
        return AuthResult::Allowed(AuthIdentity {
            method: AuthMethod::Loopback,
        });
    }

    if !store.is_setup_complete() {
        return if is_local {
            AuthResult::Allowed(AuthIdentity {
                method: AuthMethod::Loopback,
            })
        } else {
            AuthResult::SetupRequired
        };
    }

    // Check session cookie.
    if let Some(token) = cookie_header(headers).and_then(|h| parse_cookie(h, SESSION_COOKIE))
        && store.validate_session(token).await.unwrap_or(false)
    {
        return AuthResult::Allowed(AuthIdentity {
            method: AuthMethod::Password,
        });
    }

    // Check Bearer API key.
    if let Some(key) = bearer_token(headers)
        && store.verify_api_key(key).await.ok().flatten().is_some()
    {
        return AuthResult::Allowed(AuthIdentity {
            method: AuthMethod::ApiKey,
        });
    }

    AuthResult::Unauthorized
}

// ── auth_gate — covers the entire router ────────────────────────────────────

/// Middleware that applies auth to **all** routes.
///
/// Public paths (assets, auth endpoints, health, etc.) are allowed through
/// without authentication. Everything else goes through [`check_auth()`].
#[cfg(feature = "web-ui")]
pub async fn auth_gate(
    State(state): State<super::server::AppState>,
    ConnectInfo(addr): ConnectInfo<SocketAddr>,
    mut request: axum::http::Request<axum::body::Body>,
    next: Next,
) -> axum::response::Response {
    let path = request.uri().path();

    // Public paths — no auth needed.
    if is_public_path(path) {
        return next.run(request).await;
    }

    let Some(ref store) = state.gateway.credential_store else {
        // No credential store configured — pass through.
        return next.run(request).await;
    };

    let is_local = is_local_connection(request.headers(), addr, state.gateway.behind_proxy);

    match check_auth(store, request.headers(), is_local).await {
        AuthResult::Allowed(identity) => {
            request.extensions_mut().insert(identity);
            next.run(request).await
        },
        AuthResult::SetupRequired => {
            if path.starts_with("/api/") || path.starts_with("/ws/") {
                if path.starts_with("/ws/") {
                    warn!(
                        path,
                        remote = %addr,
                        is_local,
                        "auth reject: setup required for websocket connection"
                    );
                }
                (
                    StatusCode::UNAUTHORIZED,
                    Json(serde_json::json!({
                        "code": AUTH_SETUP_REQUIRED,
                        "error": "setup required"
                    })),
                )
                    .into_response()
            } else if is_local || path == "/onboarding" || path == "/onboarding/" {
                // Local connections and /onboarding pass through during
                // setup.  Local: the SPA handles onboarding redirects
                // itself.  Remote /onboarding: the page's own auth step
                // (step 0) requires a setup code, so it is safe to
                // render without full auth (#310, #350).
                request.extensions_mut().insert(AuthIdentity {
                    method: AuthMethod::Loopback,
                });
                next.run(request).await
            } else {
                // Remote connections to other pages when auth is not
                // configured yet: redirect to a static "setup required"
                // page instead of passing through, which would cause a
                // redirect loop between `/` and `/onboarding` (#350).
                Redirect::to("/setup-required").into_response()
            }
        },
        AuthResult::Unauthorized => {
            if path.starts_with("/api/") || path.starts_with("/ws/") {
                if path.starts_with("/ws/") {
                    let has_bearer = bearer_token(request.headers()).is_some();
                    let has_session_cookie = cookie_header(request.headers())
                        .is_some_and(|h| parse_cookie(h, SESSION_COOKIE).is_some());
                    warn!(
                        path,
                        remote = %addr,
                        is_local,
                        has_bearer,
                        has_session_cookie,
                        "auth reject: unauthorized websocket connection"
                    );
                }
                (
                    StatusCode::UNAUTHORIZED,
                    Json(serde_json::json!({
                        "code": AUTH_NOT_AUTHENTICATED,
                        "error": "not authenticated"
                    })),
                )
                    .into_response()
            } else {
                Redirect::to("/login").into_response()
            }
        },
    }
}

/// Paths that never require authentication.
#[cfg(feature = "web-ui")]
fn is_public_path(path: &str) -> bool {
    matches!(
        path,
        "/health" | "/auth/callback" | "/manifest.json" | "/sw.js" | "/login" | "/setup-required" | "/ws"
    ) || path.starts_with("/api/auth/")
        || path.starts_with("/api/public/")
        || path.starts_with("/api/channels/msteams/")
        || path.starts_with("/assets/")
        || path.starts_with("/share/")
}

// ── Vault guard ─────────────────────────────────────────────────────────────

/// Middleware that blocks API requests when the vault is sealed.
///
/// Returns 423 Locked for API endpoints (except auth and gon) when the vault
/// is in `Sealed` state. `Uninitialized` is not blocked — the vault doesn't
/// exist yet and there's nothing to protect.
#[cfg(feature = "vault")]
pub async fn vault_guard(
    State(state): State<super::server::AppState>,
    request: axum::http::Request<axum::body::Body>,
    next: Next,
) -> axum::response::Response {
    let Some(ref vault) = state.gateway.vault else {
        return next.run(request).await;
    };
    let path = request.uri().path();
    // Allow auth, public, gon, and non-API routes through.
    if !path.starts_with("/api/")
        || path.starts_with("/api/auth/")
        || path.starts_with("/api/public/")
        || path == "/api/gon"
    {
        return next.run(request).await;
    }
    // Only block when Sealed (not Uninitialized).
    if matches!(vault.status().await, Ok(moltis_vault::VaultStatus::Sealed)) {
        return (
            StatusCode::LOCKED,
            Json(serde_json::json!({"error": "vault is sealed", "status": "sealed"})),
        )
            .into_response();
    }
    next.run(request).await
}

// ── AuthSession extractor ───────────────────────────────────────────────────

/// Axum extractor that validates the session cookie and produces an
/// `AuthIdentity`. Returns 401 if the session is missing or invalid.
///
/// When `auth_gate` has already run, it reads the [`AuthIdentity`] the
/// middleware inserted into extensions. For auth routes (on the public
/// allowlist, where `auth_gate` skips auth), it falls back to validating
/// the session cookie directly.
pub struct AuthSession(pub AuthIdentity);

impl<S> FromRequestParts<S> for AuthSession
where
    S: Send + Sync,
    Arc<CredentialStore>: FromRef<S>,
    Arc<GatewayState>: FromRef<S>,
{
    type Rejection = (StatusCode, &'static str);

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        // If auth_gate already ran and set identity, use it.
        if let Some(id) = parts.extensions.get::<AuthIdentity>() {
            return Ok(AuthSession(id.clone()));
        }

        // Fallback for auth routes (allowlisted, middleware skipped):
        // validate session cookie directly, or check the local-bypass logic.
        let store = Arc::<CredentialStore>::from_ref(state);
        let gw = Arc::<GatewayState>::from_ref(state);

        let is_local = parts
            .extensions
            .get::<ConnectInfo<SocketAddr>>()
            .is_some_and(|ci| is_local_connection(&parts.headers, ci.0, gw.behind_proxy));

        match check_auth(&store, &parts.headers, is_local).await {
            AuthResult::Allowed(identity) => Ok(AuthSession(identity)),
            _ => Err((StatusCode::UNAUTHORIZED, "not authenticated")),
        }
    }
}

// ── Helpers ─────────────────────────────────────────────────────────────────

/// Extract the Cookie header value.
fn cookie_header(headers: &HeaderMap) -> Option<&str> {
    headers
        .get(axum::http::header::COOKIE)
        .and_then(|v| v.to_str().ok())
}

/// Extract a Bearer token from the Authorization header.
fn bearer_token(headers: &HeaderMap) -> Option<&str> {
    headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "))
}

/// Parse a specific cookie value from a Cookie header string.
pub fn parse_cookie<'a>(header: &'a str, name: &str) -> Option<&'a str> {
    for part in header.split(';') {
        let part = part.trim();
        if let Some(value) = part.strip_prefix(name)
            && let Some(value) = value.strip_prefix('=')
        {
            return Some(value);
        }
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_cookie() {
        assert_eq!(
            parse_cookie("moltis_session=abc123; other=def", "moltis_session"),
            Some("abc123")
        );
        assert_eq!(
            parse_cookie("other=def; moltis_session=xyz", "moltis_session"),
            Some("xyz")
        );
        assert_eq!(parse_cookie("other=def", "moltis_session"), None);
        assert_eq!(parse_cookie("", "moltis_session"), None);
    }

    #[cfg(feature = "web-ui")]
    #[test]
    fn terminal_ws_path_is_not_public() {
        assert!(!is_public_path("/api/terminal/ws"));
    }

    #[cfg(feature = "web-ui")]
    #[test]
    fn chat_ws_path_is_not_public() {
        assert!(!is_public_path("/ws/chat"));
    }

    #[cfg(feature = "web-ui")]
    #[test]
    fn graphql_paths_are_not_public() {
        assert!(!is_public_path("/graphql"));
    }

    #[cfg(feature = "web-ui")]
    #[test]
    fn public_identity_path_is_public() {
        assert!(is_public_path("/api/public/identity"));
    }
}

